{
  name: "get_error_distribution",
  description: `Get breakdown of error types from failed tests. Shows which error types are most common.

Fields returned per error type:
- error_type: string - Error category (e.g., "TimeoutError", "AssertionError")
- count: number - Number of occurrences
- percentage: number - Share of total failures (0-100)
- example_message: string - Sample error message`,
  inputSchema: {
    type: "object" as const,
    properties: {
      since: { type: "string", description: "Only count errors since this date (ISO 8601)" },
    },
  },
}

case "get_error_distribution": {
  const input = z.object({ since: z.string().optional() }).parse(args)

  const distribution = await db.getErrorTypeDistribution(orgId, input.since)

  return jsonResponse({
    organization: authContext.organizationSlug,
    since: input.since || "all time",
    distribution,
  })
}

export async function getErrorTypeDistribution(
  organizationId: number,
  since?: string
): Promise<Array<{ error_type: string; count: number }>> {
  const sql = getSql()

  const conditions = [
    "tr.ai_context IS NOT NULL",
    "tr.status IN ('failed', 'timedout')",
    `te.organization_id = ${organizationId}`,
  ]

  if (since) {
    conditions.push(`tr.created_at >= '${since}'`)
  }

  const whereClause = `WHERE ${conditions.join(" AND ")}`

  const query = `
    SELECT
      tr.ai_context->'error'->>'type' as error_type,
      COUNT(*) as count
    FROM test_results tr
    JOIN test_executions te ON tr.execution_id = te.id
    ${whereClause}
    GROUP BY tr.ai_context->'error'->>'type'
    ORDER BY count DESC
  `

  const result = await sql.unsafe(query)
  return result as unknown as Array<{ error_type: string; count: number }>
}

solution.updated_db_function:
interface ErrorDistributionOptions {
  since?: string
  branch?: string
  suite?: string
  limit?: number
  groupBy?: 'error_type' | 'file' | 'branch'
}

interface ErrorDistributionItem {
  error_type: string
  count: number
  percentage: number
  example_message: string | null
  files_affected?: string[]  // Only when groupBy !== 'file'
}

export async function getErrorTypeDistribution(
  organizationId: number,
  options: ErrorDistributionOptions = {}
): Promise<ErrorDistributionItem[]> {
  const sql = getSql()
  const { since, branch, suite, limit = 10, groupBy = 'error_type' } = options

  const conditions = [
    "tr.status IN ('failed', 'timedout')",
    `te.organization_id = ${organizationId}`,
  ]

  // AI context is only required when grouping by error_type
  if (groupBy === 'error_type') {
    conditions.push("tr.ai_context IS NOT NULL")
  }

  if (since) {
    conditions.push(`tr.created_at >= '${since}'`)
  }

  if (branch) {
    conditions.push(`te.branch = '${branch}'`)
  }

  if (suite) {
    conditions.push(`te.suite = '${suite}'`)
  }

  const whereClause = `WHERE ${conditions.join(" AND ")}`

  // Determine grouping column
  let groupColumn: string
  let selectColumn: string

  switch (groupBy) {
    case 'file':
      groupColumn = 'tr.test_file'
      selectColumn = 'tr.test_file as error_type'  // Reuse field name for consistency
      break
    case 'branch':
      groupColumn = 'te.branch'
      selectColumn = 'te.branch as error_type'
      break
    case 'error_type':
    default:
      groupColumn = "tr.ai_context->'error'->>'type'"
      selectColumn = "tr.ai_context->'error'->>'type' as error_type"
  }

  // Query with percentage and example_message
  const query = `
    WITH total_count AS (
      SELECT COUNT(*) as total
      FROM test_results tr
      JOIN test_executions te ON tr.execution_id = te.id
      ${whereClause}
    ),
    grouped AS (
      SELECT
        ${selectColumn},
        COUNT(*) as count,
        (SELECT error_message FROM test_results tr2 
         JOIN test_executions te2 ON tr2.execution_id = te2.id
         WHERE ${groupBy === 'error_type' 
           ? "tr2.ai_context->'error'->>'type' = " + groupColumn 
           : groupColumn + " = " + groupColumn}
           AND te2.organization_id = ${organizationId}
         ORDER BY tr2.created_at DESC LIMIT 1
        ) as example_message
      FROM test_results tr
      JOIN test_executions te ON tr.execution_id = te.id
      ${whereClause}
      GROUP BY ${groupColumn}
      ORDER BY count DESC
      LIMIT ${limit}
    )
    SELECT 
      g.error_type,
      g.count,
      ROUND((g.count::decimal / NULLIF(tc.total, 0)) * 100, 1) as percentage,
      g.example_message
    FROM grouped g, total_count tc
  `

  const result = await sql.unsafe(query)
  return result as unknown as ErrorDistributionItem[]
}

solution.updated_tool_definition:
{
  name: "get_error_distribution",
  description: `Get breakdown of error types from failed tests. Shows which error types are most common.

Supports filtering by branch, suite, and date range.

Fields returned per error type:
- error_type: string - Error category (e.g., "TimeoutError", "AssertionError")
- count: number - Number of occurrences
- percentage: number - Share of total failures (0-100)
- example_message: string | null - Sample error message from most recent occurrence`,
  inputSchema: {
    type: "object" as const,
    properties: {
      since: { 
        type: "string", 
        description: "Only count errors since this date (ISO 8601)" 
      },
      branch: { 
        type: "string", 
        description: "Filter by branch name" 
      },
      suite: { 
        type: "string", 
        description: "Filter by test suite" 
      },
      limit: { 
        type: "number", 
        default: 10,
        description: "Max error types to return (default: 10)" 
      },
      group_by: {
        type: "string",
        enum: ["error_type", "file", "branch"],
        description: "How to group errors. Default: error_type",
      },
    },
  },
}

solution.updated_tool_handler:
case "get_error_distribution": {
  const input = z
    .object({
      since: z.string().optional(),
      branch: z.string().optional(),
      suite: z.string().optional(),
      limit: z.number().min(1).max(100).default(10),
      group_by: z.enum(["error_type", "file", "branch"]).default("error_type"),
    })
    .parse(args)

  const distribution = await db.getErrorTypeDistribution(orgId, {
    since: input.since,
    branch: input.branch,
    suite: input.suite,
    limit: input.limit,
    groupBy: input.group_by,
  })

  return jsonResponse({
    organization: authContext.organizationSlug,
    filters: {
      since: input.since || "all time",
      branch: input.branch || "all",
      suite: input.suite || "all",
    },
    group_by: input.group_by,
    total_types: distribution.length,
    distribution,
  })
}
